<?php
declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('orders.view');$id=cmsId($_GET['id']??0);$pdo=obtenerConexion();$q=$pdo->prepare('SELECT d.*,p.numero,p.total,u.nombre,u.apellido,u.correo FROM dte_documentos d JOIN pedidos p ON p.id=d.pedido_id JOIN usuarios u ON u.id=p.usuario_id WHERE d.id=:id');$q->execute(['id'=>$id]);$d=$q->fetch();if(!$d){cmsFlash('error','DTE no encontrado.');header('Location:index.php');exit;}$q=$pdo->prepare('SELECT * FROM dte_eventos WHERE dte_id=:id OR pedido_id=:p ORDER BY created_at DESC,id DESC LIMIT 100');$q->execute(['id'=>$id,'p'=>$d['pedido_id']]);$eventos=$q->fetchAll();cmsCabecera('DTE '.$d['numero_control'],'facturas/index.php');?>
<div class="row"><div class="col-lg-8"><div class="card card-rounded"><div class="card-body"><h2 class="h5">Eventos del proveedor</h2><div class="table-responsive"><table class="table"><thead><tr><th>Fecha</th><th>Operación</th><th>Resultado</th><th>Código</th><th>Observación</th></tr></thead><tbody><?php foreach($eventos as$e):?><tr><td><?=date('d/m/Y H:i',strtotime($e['created_at']))?></td><td><?=atenea_e($e['operacion'])?></td><td><?=atenea_e($e['resultado'])?></td><td><?=atenea_e((string)$e['codigo'])?></td><td><?=atenea_e((string)$e['observaciones'])?></td></tr><?php endforeach;?></tbody></table></div></div></div></div><div class="col-lg-4"><div class="card card-rounded"><div class="card-body"><p><strong>Pedido:</strong> <a href="../pedidos/detalle.php?id=<?=$d['pedido_id']?>"><?=atenea_e($d['numero'])?></a><br><strong>Cliente:</strong> <?=atenea_e(trim($d['nombre'].' '.$d['apellido']))?><br><strong>Estado:</strong> <?=atenea_e($d['estado'])?><br><strong>Ambiente:</strong> <?=atenea_e($d['ambiente'])?><br><strong>Sello:</strong> <?=atenea_e((string)$d['sello_recepcion'])?></p><a class="btn btn-primary w-100 mb-2" target="_blank" href="../../dte/documento.php?pedido=<?=$d['pedido_id']?>">Ver PDF</a><a class="btn btn-outline-primary w-100 mb-2" href="../../dte/documento.php?pedido=<?=$d['pedido_id']?>&descargar=1">Descargar PDF</a><a class="btn btn-outline-primary w-100" href="../../dte/documento.php?pedido=<?=$d['pedido_id']?>&tipo=json&descargar=1">Descargar JSON</a><?php if(usuarioTienePermiso('dte.manage')):?><form method="post" action="accion.php" class="mt-3"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="id" value="<?=$id?>"><select class="form-select mb-2" name="accion"><option value="consultar">Consultar estado</option><option value="invalidar">Invalidar</option></select><textarea class="form-control mb-2" name="motivo" maxlength="500" placeholder="Motivo obligatorio al invalidar"></textarea><button class="btn btn-warning w-100">Ejecutar mediante provider</button></form><?php endif;?></div></div></div></div><?php cmsPie();
